}

button {
  border: 0;
}

.app-shell {
  width: min(1120px, calc(100% - 32px));
  margin: 0 auto;
  padding: 24px 0 48px;
  display: grid;
  gap: 20px;
}

.panel {
  position: relative;
  overflow: hidden;
  border: 1px solid var(--panel-border);
