  inset: 0;
  background: linear-gradient(140deg, rgba(15, 118, 110, 0.08), transparent 55%);
  pointer-events: none;
}

.hero {
  padding: 28px;
}

.welcome-hero {
  min-height: 56vh;
  display: grid;
  align-content: center;
  gap: 18px;
}

.eyebrow {
  margin: 0;
