  justify-content: space-between;
  align-items: end;
  gap: 16px;
}

.score-card h2 {
  margin-bottom: 0;
  font-size: clamp(2rem, 5vw, 3rem);
}

.score-card .helper {
  max-width: 42ch;
}

.dashboard-grid {
  display: grid;
  gap: 18px;
}

.section-card {
  min-height: 100%;
}

.priority-list {
  margin: 0;
  padding: 0;
  list-style: none;
  display: grid;
  gap: 12px;
}

.health-item {
  border: 1px solid rgba(148, 163, 184, 0.24);
  border-radius: 18px;
  background: rgba(248, 250, 252, 0.88);
  padding: 14px;
}

.health-item p {
  margin: 10px 0 0;
  color: var(--text-muted);
}

.health-item-header {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
  justify-content: space-between;
  align-items: center;
}

.health-item-title {
  font-weight: 700;
}

.badge {
  display: inline-flex;
  align-items: center;
  min-height: 28px;
  padding: 0 10px;
  border-radius: 999px;
  background: rgba(15, 118, 110, 0.12);
  color: var(--accent-strong);
  font-size: 0.82rem;
  font-weight: 700;
}

.loading-mark {
  width: 52px;
  height: 52px;
  border-radius: 50%;
  border: 4px solid rgba(15, 118, 110, 0.14);
  border-top-color: var(--accent);
  animation: spin 900ms linear infinite;
}

.generating-panel {
  display: grid;
  gap: 18px;
  align-content: start;
  min-height: 46vh;
}

@keyframes fade-up {
  from {
    opacity: 0;
    transform: translateY(8px);
  }

  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes spin {
  to {
    transform: rotate(360deg);
  }
}

@media (min-width: 760px) {
  .app-shell {
    padding: 36px 0 56px;
    gap: 24px;
  }

  .dashboard-grid {
    grid-template-columns: repeat(3, minmax(0, 1fr));
  }
}

@media (max-width: 640px) {
  .app-shell {
    width: min(100% - 20px, 1120px);
    padding: 16px 0 32px;
  }

  .panel {
    border-radius: 20px;
    padding: 20px;
  }

  .welcome-hero {
    min-height: auto;
    padding-top: 34px;
    padding-bottom: 34px;
  }

  .score-card {
    align-items: start;
  }

  .primary,
  .secondary {
    width: 100%;
    justify-content: center;
  }
